import di.commonModule
import di.iosModule
import org.koin.core.context.startKoin
import platform.UIKit.UIViewController
import presentation.view.atoms.theme.FeatureUITheme

fun MainViewController(): UIViewController {
    if (!IosViewModelHolder.isInitialized()) {
        val koin = startKoin {
            modules(commonModule, iosModule)
        }.koin
        IosViewModelHolder.chatBotViewModel = koin.get()
        IosViewModelHolder.authViewModel    = koin.get()
        IosViewModelHolder.menuViewModel    = koin.get()
    }

    return ComposeUIViewController {
        // TEST 4: Scaffold + OutlinedTextField
        FeatureUITheme(darkTheme = false) {
            Scaffold { padding ->
                Box(
                    modifier = Modifier.fillMaxSize().padding(padding),
                    contentAlignment = Alignment.Center
                ) {
                    Column(
                        horizontalAlignment = Alignment.CenterHorizontally,
                        modifier = Modifier.padding(32.dp)
                    ) {
                        Text("Test TextField", style = MaterialTheme.typography.headlineMedium)
                        Spacer(Modifier.height(16.dp))

                        var text by remember { mutableStateOf("") }
                        OutlinedTextField(
                            value = text,
                            onValueChange = { text = it },
                            label = { Text("Escribe aquí") },
                            modifier = Modifier.fillMaxWidth()
                        )

                        Spacer(Modifier.height(16.dp))
                        Button(onClick = { }) { Text("OK") }
                    }
                }
            }
        }
    }
}

