package core.utils

object Constans {
    // Endpoint compartido: Android usa Bearer token, iOS usa email+password en body
    const val GEMINI_FUNCTION_URL = "https://us-central1-portfolio-app-9a4bc.cloudfunctions.net/askGemini"
    const val GEMINI_DIRECT_URL = "https://generativelanguage.googleapis.com/v1beta/models/gemini-1.5-flash:generateContent"
}

import androidx.compose.ui.window.ComposeUIViewController
import di.IosViewModelHolder
import di.commonModule
import di.iosModule
import kotlinx.coroutines.runBlocking
import org.koin.core.context.startKoin
import platform.UIKit.UIViewController

fun MainViewController(): UIViewController {
    if (!IosViewModelHolder.isInitialized()) {
        val koin = startKoin {
            modules(commonModule, iosModule)
        }.koin
        IosViewModelHolder.chatBotViewModel = koin.get()
        IosViewModelHolder.authViewModel    = koin.get()
        IosViewModelHolder.menuViewModel    = koin.get()

        // Precargar imágenes PNG sincrónicamente antes del primer frame de Compose
        // El bundle está en local → runBlocking es seguro y rápido aquí
        runBlocking {
            IosViewModelHolder.preloadBitmaps()
        }
    }

    return ComposeUIViewController {
        App()
    }
}

import androidx.compose.ui.window.ComposeUIViewController
import di.IosViewModelHolder
import di.commonModule
import di.iosModule
import org.koin.core.context.startKoin
import platform.UIKit.UIViewController

@Suppress("unused") // llamada desde Swift: MainiOSKt.MainViewController()
fun MainViewController(): UIViewController {
    if (!IosViewModelHolder.isInitialized()) {
        val koin = startKoin {
            modules(commonModule, iosModule)
        }.koin
        IosViewModelHolder.chatBotViewModel = koin.get()
        IosViewModelHolder.authViewModel    = koin.get()
        IosViewModelHolder.menuViewModel    = koin.get()

        // Precargar imágenes usando Foundation directamente (síncrono, sin corrutinas)
        IosViewModelHolder.preloadBitmaps()
    }

    return ComposeUIViewController {
        App()
    }
}

package core.service

import domain.model.ChatBotMessage
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext
import presentation.view.organisms.PlatformBitmap

/**
 * Implementación iOS de TextRecognitionService.
 * Stub funcional — para OCR real usar Vision framework con wrapper Swift.
 */
class TextRecognitionServiceImpl : TextRecognitionService {
    override suspend fun recognizeText(imageData: ByteArray): String {
        return "Texto extraído vía Vision (iOS) - pendiente de integración nativa"
    }
}

/**
 * Implementación iOS de GeminiCloudService.
 * Stub para iOS - implementación completa requiere NSURLSession con interop Swift
 * o integración con URLSession mediante wrapper Swift.
 *
 * Para producción:
 * 1. Crear wrapper Swift que encapsule URLSession
 * 2. Exportarlo a Kotlin via @ObjC
 * 3. Llamarlo desde aquí
 */
class GeminiCloudServiceImpl : GeminiCloudService {

    override suspend fun analyzeImage(bitmap: PlatformBitmap): String {
        return withContext(Dispatchers.Default) {
            try {
                "Análisis de imagen completado. " +
                "Se han identificado elementos visuales en la imagen. " +
                "Para OCR real, requiere integración con Vision framework."
            } catch (e: Exception) {
                "Error al analizar la imagen en iOS: ${e.message}"
            }
        }
    }

    override suspend fun solveProblem(problem: String): String {
        return withContext(Dispatchers.Default) {
            try {
                buildString {
                    append("Solución al problema:\n\n")
                    append(problem.take(200))
                    append("\n\n")
                    append("Pasos sugeridos:\n")
                    append("1. Analiza cuidadosamente el problema\n")
                    append("2. Identifica los componentes principales\n")
                    append("3. Aplica razonamiento paso a paso\n")
                    append("4. Verifica tu solución\n\n")
                    append("Nota: Para respuestas de Gemini real, configura:\n")
                    append("- Cloud Function con GEMINI_API_KEY\n")
                    append("- Autenticación Firebase en iOS")
                }
            } catch (e: Exception) {
                "Error al resolver el problema en iOS: ${e.message}"
            }
        }
    }

    override suspend fun continueChat(
        messages: List<ChatBotMessage>,
        newMessage: String
    ): String {
        return withContext(Dispatchers.Default) {
            try {
                val historyText = messages.joinToString("\n") { msg ->
                    if (msg.isFromUser) "Tú: ${msg.text}" else "Asistente: ${msg.text}"
                }

                buildString {
                    if (historyText.isNotEmpty()) {
                        append("Historial:\n")
                        append(historyText.take(300))
                        append("\n\n")
                    }
                    append("Tu pregunta: $newMessage\n\n")
                    append("Respuesta:\n")
                    append("Estoy procesando tu pregunta. Para respuestas completas de Gemini, ")
                    append("asegúrate de que tu Cloud Function esté correctamente configurada ")
                    append("con Firebase Auth y Gemini API Key.")
                }
            } catch (e: Exception) {
                "Error al procesar la consulta en iOS: ${e.message}"
            }
        }
    }
}

package core.service

import core.utils.Constans
import di.IosViewModelHolder
import domain.model.ChatBotMessage
import kotlinx.cinterop.BetaInteropApi
import kotlinx.cinterop.ExperimentalForeignApi
import kotlinx.cinterop.addressOf
import kotlinx.cinterop.usePinned
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.suspendCancellableCoroutine
import kotlinx.coroutines.withContext
import platform.Foundation.*
import kotlin.coroutines.resume

class TextRecognitionServiceImpl : TextRecognitionService {
    override suspend fun recognizeText(imageData: ByteArray): String =
        "Texto extraído vía Vision (iOS) - pendiente de integración nativa"
}

/**
 * Implementación iOS de GeminiCloudService.
 *
 * Usa el endpoint askGeminiIos que maneja Firebase Auth en el servidor.
 * iOS solo envía {email, password, message, conversationHistory}.
 * Sin ninguna API key en el cliente — igual que Android pero el servidor hace la auth.
 */
class GeminiCloudServiceImpl : GeminiCloudService {

    override suspend fun analyzeImage(bitmap: presentation.view.organisms.PlatformBitmap): String =
        callIosFunction(
            message = "Analiza la siguiente imagen y describe su contenido de manera educativa.",
            history = emptyList()
        )

    override suspend fun solveProblem(problem: String): String =
        callIosFunction(message = problem, history = emptyList())

    override suspend fun continueChat(
        messages: List<ChatBotMessage>,
        newMessage: String
    ): String = callIosFunction(message = newMessage, history = messages)

    private suspend fun callIosFunction(
        message: String,
        history: List<ChatBotMessage>
    ): String = withContext(Dispatchers.Default) {

        val email    = IosViewModelHolder.savedEmail
            ?: return@withContext "Error: no hay sesión activa. Por favor inicia sesión."
        val password = IosViewModelHolder.savedPassword
            ?: return@withContext "Error: no hay sesión activa. Por favor inicia sesión."

        val body = buildRequestJson(email, password, message, history)

        try {
            val responseText = postRequest(Constans.GEMINI_FUNCTION_URL, body)
            extractJsonField(responseText, "response")
                ?: extractJsonField(responseText, "error")
                ?: "Error: respuesta inesperada del servidor."
        } catch (e: Exception) {
            println("[iOS] GeminiCloudService error: ${e.message}")
            "Error al conectar con el servidor: ${e.message}"
        }
    }

    private fun buildRequestJson(
        email: String,
        password: String,
        message: String,
        history: List<ChatBotMessage>
    ): String {
        fun String.esc() = replace("\\", "\\\\").replace("\"", "\\\"")
            .replace("\n", "\\n").replace("\r", "\\r")

        return buildString {
            append("{")
            append("\"email\":\"${email.esc()}\",")
            append("\"password\":\"${password.esc()}\",")
            append("\"message\":\"${message.esc()}\"")
            if (history.isNotEmpty()) {
                append(",\"conversationHistory\":[")
                history.forEachIndexed { i, msg ->
                    append("{\"text\":\"${msg.text.esc()}\",\"isUser\":${msg.isFromUser}}")
                    if (i < history.size - 1) append(",")
                }
                append("]")
            }
            append("}")
        }
    }

    @OptIn(ExperimentalForeignApi::class, BetaInteropApi::class)
    private suspend fun postRequest(url: String, body: String): String {
        val nsUrl = NSURL.URLWithString(url) ?: throw Exception("URL inválida")
        val request = NSMutableURLRequest.requestWithURL(
            URL = nsUrl,
            cachePolicy = platform.Foundation.NSURLRequestUseProtocolCachePolicy,
            timeoutInterval = 30.0
        ).apply {
            HTTPMethod = "POST"
            setValue("application/json", forHTTPHeaderField = "Content-Type")
            HTTPBody = body.encodeToByteArray().toNSData()
        }
        return suspendCancellableCoroutine<String> { cont ->
            NSURLSession.sharedSession.dataTaskWithRequest(request) { data, response, error ->
                if (error != null || data == null) {
                    cont.resume("Error: ${error?.localizedDescription ?: "sin datos"}")
                    return@dataTaskWithRequest
                }
                val httpStatus = (response as? NSHTTPURLResponse)?.statusCode ?: 0
                println("[iOS] askGeminiIos status: $httpStatus")
                val text = NSString.create(data, NSUTF8StringEncoding)?.toString() ?: ""
                cont.resume(text)
            }.resume()
        }
    }

    private fun extractJsonField(json: String, field: String): String? {
        val key = "\"$field\":\""
        val start = json.indexOf(key).takeIf { it >= 0 } ?: return null
        val valueStart = start + key.length
        val valueEnd   = json.indexOf('"', valueStart).takeIf { it >= 0 } ?: return null
        return json.substring(valueStart, valueEnd).ifBlank { null }
    }
}

@OptIn(ExperimentalForeignApi::class, BetaInteropApi::class)
private fun ByteArray.toNSData(): NSData =
    if (isEmpty()) NSData()
    else usePinned { pinned ->
        NSData.create(bytes = pinned.addressOf(0), length = size.toULong())
    }

package data.repository

import domain.model.UserModel
import domain.repositories.AuthRepository

/**
 * Implementación iOS de AuthRepository.
 *
 * Estado actual: stub funcional para desarrollo con Xcode Simulator.
 *
 * Para producción con Firebase Auth real se requiere:
 * 1. Agregar pod 'Firebase/Auth' en iosApp/Podfile
 * 2. Inicializar Firebase en el @main de la app iOS (ver MainiOS.kt)
 * 3. Crear wrapper Swift que exponga FirebaseAuth a Kotlin vía @ObjCClass
 * 4. Reemplazar el stub de signInWithEmail con la llamada al wrapper.
 */
class IosAuthRepositoryImpl : AuthRepository {

    // Sesión en memoria (reemplazar con Keychain en producción)
    private var currentUser: UserModel? = null

    override suspend fun signInWithEmail(email: String, password: String): Result<UserModel> {
        return try {
            // TODO: Reemplazar con FirebaseAuth iOS SDK real
            if (email.isNotBlank() && password.length >= 6) {
                val user = UserModel(
                    id = "ios-${email.hashCode()}",
                    email = email,
                    userName = email.substringBefore("@"),
                    userCode = email
                )
                currentUser = user
                println("[iOS] AuthRepository: Login exitoso - $email")
                Result.success(user)
            } else {
                Result.failure(Exception("Email o contraseña inválidos"))
            }
        } catch (e: Exception) {
            println("[iOS] AuthRepository: Error - ${e.message}")
            Result.failure(e)
        }
    }

    override suspend fun signInWithGoogle(): Result<UserModel> {
        // TODO: Integrar Google Sign-In para iOS
        return Result.failure(Exception("Google Sign-In no disponible aún en iOS"))
    }

    override suspend fun signUp(email: String, password: String, name: String): Result<UserModel> {
        return try {
            // TODO: Reemplazar con FirebaseAuth createUser iOS SDK real
            if (email.isNotBlank() && password.length >= 6 && name.isNotBlank()) {
                val user = UserModel(
                    id = "ios-new-${email.hashCode()}",
                    email = email,
                    userName = name,
                    userCode = email
                )
                currentUser = user
                Result.success(user)
            } else {
                Result.failure(Exception("Datos de registro inválidos"))
            }
        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    override suspend fun signOut(): Result<Unit> {
        return try {
            // TODO: Llamar a FirebaseAuth.signOut() iOS SDK real
            currentUser = null
            println("[iOS] AuthRepository: Sesión cerrada")
            Result.success(Unit)
        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    override fun getCurrentUser(): UserModel? = currentUser
}

package data.repository

import di.IosViewModelHolder
import domain.model.UserModel
import domain.repositories.AuthRepository

/**
 * Implementación iOS de AuthRepository.
 * Guarda email y password en IosViewModelHolder para que
 * GeminiCloudServiceImpl los use al llamar a askGeminiIos.
 * La autenticación real contra Firebase la hace el servidor.
 */
class IosAuthRepositoryImpl : AuthRepository {

    private var currentUser: UserModel? = null

    override suspend fun signInWithEmail(email: String, password: String): Result<UserModel> {
        if (email.isBlank() || password.length < 6) {
            return Result.failure(Exception("Email o contraseña inválidos"))
        }
        // Guardar en memoria — el servidor validará las credenciales al enviar cada mensaje
        IosViewModelHolder.savedEmail    = email
        IosViewModelHolder.savedPassword = password

        val user = UserModel(
            id       = "ios-${email.hashCode()}",
            email    = email,
            userName = email.substringBefore("@"),
            userCode = email
        )
        currentUser = user
        println("[iOS] AuthRepository: credenciales guardadas para $email")
        return Result.success(user)
    }

    override suspend fun signInWithGoogle(): Result<UserModel> =
        Result.failure(Exception("Google Sign-In no disponible en iOS"))

    override suspend fun signUp(email: String, password: String, name: String): Result<UserModel> =
        Result.failure(Exception("Registro no disponible en iOS"))

    override suspend fun signOut(): Result<Unit> {
        currentUser = null
        IosViewModelHolder.savedEmail    = null
        IosViewModelHolder.savedPassword = null
        IosViewModelHolder.firebaseIdToken = null
        println("[iOS] AuthRepository: sesión cerrada")
        return Result.success(Unit)
    }

    override fun getCurrentUser(): UserModel? = currentUser
}

package di

import androidx.compose.ui.graphics.ImageBitmap
import androidx.compose.ui.graphics.toComposeImageBitmap
import org.jetbrains.compose.resources.ExperimentalResourceApi
import portafolio_kotlin.shared.generated.resources.Res
import presentation.viewmodels.AuthViewModel
import presentation.viewmodels.ChatBotViewModel
import presentation.viewmodels.MenuViewModel
import org.jetbrains.skia.Image as SkiaImage

/**
 * Holder de ViewModels para iOS.
 * Evita depender de composition locals de Koin (que fallan en Kotlin/Native).
 * Los ViewModels se inicializan una sola vez desde MainViewController.
 */
object IosViewModelHolder {
    var chatBotViewModel: ChatBotViewModel? = null
    var authViewModel: AuthViewModel? = null
    var menuViewModel: MenuViewModel? = null

    /** Bitmaps precargados al inicio — disponibles desde el primer frame de Compose */
    val preloadedBitmaps = mutableMapOf<String, ImageBitmap>()

    fun isInitialized() = chatBotViewModel != null

    @OptIn(ExperimentalResourceApi::class)
    suspend fun preloadBitmaps() {
        val paths = listOf(
            "drawable/capibara_family_not_background.png"
        )
        for (path in paths) {
            runCatching {
                val bytes = Res.readBytes(path)
                preloadedBitmaps[path] = SkiaImage.makeFromEncoded(bytes).toComposeImageBitmap()
                println("IosViewModelHolder: ✅ precargado $path (${bytes.size} bytes)")
            }.onFailure { e ->
                println("IosViewModelHolder: ❌ error precargando $path → ${e.message}")
            }
        }
    }
}

package di
import androidx.compose.ui.graphics.ImageBitmap import androidx.compose.ui.graphics.toComposeImageBitmap import kotlinx.cinterop.ExperimentalForeignApi import kotlinx.cinterop.addressOf import kotlinx.cinterop.usePinned import platform.Foundation.NSBundle import platform.Foundation.NSData import platform.Foundation.dataWithContentsOfFile import platform.posix.memcpy import presentation.viewmodels.AuthViewModel import presentation.viewmodels.ChatBotViewModel import presentation.viewmodels.MenuViewModel import org.jetbrains.skia.Image as SkiaImage
/** * Holder de ViewModels para iOS. * Evita depender de composition locals de Koin (que fallan en Kotlin/Native). * Los ViewModels se inicializan una sola vez desde MainViewController. */ object IosViewModelHolder { var chatBotViewModel: ChatBotViewModel? = null var authViewModel: AuthViewModel? = null var menuViewModel: MenuViewModel? = null
/** Firebase ID Token — obtenido vía REST API al hacer login */ var firebaseIdToken: String? = null /** Credenciales en memoria para re-autenticar si el token expira */ var savedEmail: String? = null var savedPassword: String? = null
/** Bitmaps precargados al inicio — disponibles desde el primer frame de Compose */ val preloadedBitmaps = mutableMapOf<String, ImageBitmap>()
fun isInitialized() = chatBotViewModel != null
@OptIn(ExperimentalForeignApi::class) fun preloadBitmaps() { val resourcePaths = listOf( "drawable/capibara_family_not_background.png" ) val bundlePath = NSBundle.mainBundle.bundlePath for (path in resourcePaths) { runCatching { val fullPath = "$bundlePath/composeResources/portafolio_kotlin.shared.generated.resources/$path" val data = NSData.dataWithContentsOfFile(fullPath) ?: throw IllegalStateException("Archivo no encontrado: $fullPath")
val bytes = ByteArray(data.length.toInt()) bytes.usePinned { pinned -> memcpy(pinned.addressOf(0), data.bytes, data.length) }
val skiaImage = SkiaImage.makeFromEncoded(bytes) ?: throw IllegalStateException("No se pudo decodificar la imagen: $path")
preloadedBitmaps[path] = skiaImage.toComposeImageBitmap() println("IosViewModelHolder: ✅ precargado $path (${bytes.size} bytes)") }.onFailure { e -> println("IosViewModelHolder: ❌ error precargando $path → ${e.message}") } } } }

package presentation.view.atoms
import androidx.compose.runtime.Composable import androidx.compose.ui.graphics.Color import androidx.compose.ui.graphics.painter.BitmapPainter import androidx.compose.ui.graphics.painter.ColorPainter import androidx.compose.ui.graphics.painter.Painter import di.IosViewModelHolder import org.jetbrains.compose.resources.DrawableResource
/** * Carga PNG/JPG desde los bitmaps precargados en IosViewModelHolder. * Las imágenes se decodifican UNA vez en MainViewController (antes del primer * frame de Compose) y se reutilizan aquí sin ninguna I/O ni painterResource. */ @Composable actual fun safeImagePainter(resource: DrawableResource, resourcePath: String): Painter { val bitmap = IosViewModelHolder.preloadedBitmaps[resourcePath] return bitmap?.let { BitmapPainter(it) } ?: ColorPainter(Color.Transparent) }

package presentation.view.atoms

import androidx.compose.runtime.Composable
import androidx.compose.ui.graphics.painter.BitmapPainter
import androidx.compose.ui.graphics.painter.Painter
import di.IosViewModelHolder
import org.jetbrains.compose.resources.DrawableResource
import org.jetbrains.compose.resources.painterResource

/**
 * iOS: Carga imágenes PNG desde los bitmaps precargados en IosViewModelHolder (ruta rápida).
 * Si el bitmap no está disponible (preloading falló), usa painterResource como fallback.
 * NOTA: painterResource es seguro para PNGs en CMP 1.8.0.
 *       El crash _NSCFNumber solo afecta a XML vector drawables (iconos), no a PNGs.
 */
@Composable
actual fun safeImagePainter(resource: DrawableResource, resourcePath: String): Painter {
    // Ruta rápida: bitmap precargado al inicio (sin I/O en composición)
    val bitmap = IosViewModelHolder.preloadedBitmaps[resourcePath]
    if (bitmap != null) return BitmapPainter(bitmap)

    // Fallback: painterResource estándar de CMP (funciona para PNG en CMP 1.8.0)
    return painterResource(resource)
}

